import React, { useState, useEffect } from 'react';
import './LoadingMessage.css';

const STAGES = [
  'Parsing your question…',
  'Generating pandas query…',
  'Executing against DataFrame…',
  'Interpreting results…',
];

export default function LoadingMessage() {
  const [stage, setStage] = useState(0);

  useEffect(() => {
    const id = setInterval(() => setStage(s => Math.min(s + 1, STAGES.length - 1)), 1800);
    return () => clearInterval(id);
  }, []);

  return (
    <div className="loading-message">
      <div className="loading-avatar">✦</div>
      <div className="loading-body">
        <span className="loading-role">FLIGHTIQ</span>
        <div className="loading-bubble">
          <div className="loading-stages">
            {STAGES.map((s, i) => (
              <div key={i} className={`loading-stage ${i < stage ? 'done' : i === stage ? 'active' : 'pending'}`}>
                <span className="stage-icon">{i < stage ? '✓' : i === stage ? '›' : '·'}</span>
                <span>{s}</span>
              </div>
            ))}
          </div>
          <div className="loading-bar">
            <div className="loading-fill" style={{ width: `${((stage + 1) / STAGES.length) * 100}%` }} />
          </div>
        </div>
      </div>
    </div>
  );
}
